import{_ as n,c as t,o as r,a1 as s}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"KI-Agenten: Vorstellung von 10 Experten | oh-my-opencode","description":"Lernen Sie die 10 KI-Agenten von oh-my-opencode kennen. Wählen Sie Agenten basierend auf dem Aufgabentyp aus, um effiziente Zusammenarbeit und parallele Ausführung zu erreichen.","frontmatter":{"title":"KI-Agenten: Vorstellung von 10 Experten | oh-my-opencode","sidebarTitle":"Lernen Sie 10 KI-Experten kennen","subtitle":"KI-Agenten: Vorstellung von 10 Experten","description":"Lernen Sie die 10 KI-Agenten von oh-my-opencode kennen. Wählen Sie Agenten basierend auf dem Aufgabentyp aus, um effiziente Zusammenarbeit und parallele Ausführung zu erreichen.","tags":["ai-agents","orchestration"],"prerequisite":["start-sisyphus-orchestrator"],"order":60},"headers":[],"relativePath":"de/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md","filePath":"de/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"}'),a={name:"de/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"};function i(o,e,l,d,u,g){return r(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="ki-agenten-team-vorstellung-von-10-experten" tabindex="-1">KI-Agenten-Team: Vorstellung von 10 Experten <a class="header-anchor" href="#ki-agenten-team-vorstellung-von-10-experten" aria-label="Permalink to &quot;KI-Agenten-Team: Vorstellung von 10 Experten&quot;">​</a></h1><h2 id="was-sie-lernen-werden" tabindex="-1">Was Sie lernen werden <a class="header-anchor" href="#was-sie-lernen-werden" aria-label="Permalink to &quot;Was Sie lernen werden&quot;">​</a></h2><ul><li>Die Verantwortlichkeiten und Fachgebiete der 10 integrierten KI-Agenten verstehen</li><li>Schnell den am besten geeigneten Agenten basierend auf dem Aufgabentyp auswählen</li><li>Die Zusammenarbeitsmechanismen zwischen Agenten verstehen (Delegation, Parallelität, Review)</li><li>Die Berechtigungsbeschränkungen und Anwendungsszenarien verschiedener Agenten beherrschen</li></ul><h2 id="kerngedanke-zusammenarbeit-wie-ein-echtes-team" tabindex="-1">Kerngedanke: Zusammenarbeit wie ein echtes Team <a class="header-anchor" href="#kerngedanke-zusammenarbeit-wie-ein-echtes-team" aria-label="Permalink to &quot;Kerngedanke: Zusammenarbeit wie ein echtes Team&quot;">​</a></h2><p>Die Kernidee von <strong>oh-my-opencode</strong> ist: <strong>Behandeln Sie KI nicht als einen Alleskönner, sondern als ein professionelles Team</strong>.</p><p>In einem echten Entwicklungsteam benötigen Sie:</p><ul><li><strong>Hauptorchestrator</strong> (Tech Lead): Verantwortlich für Planung, Aufgabenverteilung und Fortschrittsverfolgung</li><li><strong>Architekturberater</strong> (Architect): Bietet technische Entscheidungen und Architekturdesign-Empfehlungen</li><li><strong>Code-Reviewer</strong> (Reviewer): Überprüft Code-Qualität und findet potenzielle Probleme</li><li><strong>Forschungsexperte</strong> (Researcher): Sucht Dokumentation, Open-Source-Implementierungen und Best Practices</li><li><strong>Code-Detektiv</strong> (Searcher): Lokalisiert schnell Code, findet Referenzen und versteht bestehende Implementierungen</li><li><strong>Frontend-Designer</strong> (Frontend Designer): Entwirft UI und passt Stile an</li><li><strong>Git-Experte</strong> (Git Master): Committet Code, verwaltet Branches und durchsucht Historie</li></ul><p>oh-my-opencode hat diese Rollen in 10 spezialisierte KI-Agenten umgesetzt, die Sie flexibel je nach Aufgabentyp kombinieren können.</p><h2 id="detaillierte-vorstellung-der-10-agenten" tabindex="-1">Detaillierte Vorstellung der 10 Agenten <a class="header-anchor" href="#detaillierte-vorstellung-der-10-agenten" aria-label="Permalink to &quot;Detaillierte Vorstellung der 10 Agenten&quot;">​</a></h2><h3 id="hauptorchestratoren-2" tabindex="-1">Hauptorchestratoren (2) <a class="header-anchor" href="#hauptorchestratoren-2" aria-label="Permalink to &quot;Hauptorchestratoren (2)&quot;">​</a></h3><h4 id="sisyphus-hauptorchestrator" tabindex="-1">Sisyphus - Hauptorchestrator <a class="header-anchor" href="#sisyphus-hauptorchestrator" aria-label="Permalink to &quot;Sisyphus - Hauptorchestrator&quot;">​</a></h4><p><strong>Rolle</strong>: Hauptorchestrator, Ihr primärer Tech Lead</p><p><strong>Fähigkeiten</strong>:</p><ul><li>Tiefes Reasoning (32k thinking budget)</li><li>Planung und Delegation komplexer Aufgaben</li><li>Ausführung von Code-Modifikationen und Refactoring</li><li>Verwaltung des gesamten Entwicklungsprozesses</li></ul><p><strong>Empfohlenes Modell</strong>: <code>anthropic/claude-opus-4-5</code> (temperature: 0.1)</p><p><strong>Anwendungsszenarien</strong>:</p><ul><li>Tägliche Entwicklungsaufgaben (neue Features, Bug-Fixes)</li><li>Komplexe Probleme, die tiefes Reasoning erfordern</li><li>Mehrstufige Aufgabenzerlegung und -ausführung</li><li>Szenarien, die parallele Delegation an andere Agenten erfordern</li></ul><p><strong>Aufrufmethode</strong>:</p><ul><li>Standard-Hauptagent (im OpenCode Agent Selector &quot;Sisyphus&quot;)</li><li>Direkte Eingabe der Aufgabe im Prompt, keine speziellen Trigger-Wörter erforderlich</li></ul><p><strong>Berechtigungen</strong>: Vollständige Tool-Berechtigungen (write, edit, bash, delegate_task usw.)</p><hr><h4 id="atlas-todo-manager" tabindex="-1">Atlas - TODO-Manager <a class="header-anchor" href="#atlas-todo-manager" aria-label="Permalink to &quot;Atlas - TODO-Manager&quot;">​</a></h4><p><strong>Rolle</strong>: Hauptorchestrator, spezialisiert auf TODO-Listen-Management und Aufgabenausführungsverfolgung</p><p><strong>Fähigkeiten</strong>:</p><ul><li>Verwaltung und Verfolgung von TODO-Listen</li><li>Systematische Ausführungsplanung</li><li>Aufgabenfortschrittsüberwachung</li></ul><p><strong>Empfohlenes Modell</strong>: <code>anthropic/claude-opus-4-5</code> (temperature: 0.1)</p><p><strong>Anwendungsszenarien</strong>:</p><ul><li>Projektausführung mit dem Befehl <code>/start-work</code> starten</li><li>Aufgaben streng nach Plan abschließen</li><li>Systematische Verfolgung des Aufgabenfortschritts</li></ul><p><strong>Aufrufmethode</strong>:</p><ul><li>Verwendung des Slash-Befehls <code>/start-work</code></li><li>Automatische Aktivierung über Atlas Hook</li></ul><p><strong>Berechtigungen</strong>: Vollständige Tool-Berechtigungen</p><hr><h3 id="berater-und-reviewer-3" tabindex="-1">Berater und Reviewer (3) <a class="header-anchor" href="#berater-und-reviewer-3" aria-label="Permalink to &quot;Berater und Reviewer (3)&quot;">​</a></h3><h4 id="oracle-strategischer-berater" tabindex="-1">Oracle - Strategischer Berater <a class="header-anchor" href="#oracle-strategischer-berater" aria-label="Permalink to &quot;Oracle - Strategischer Berater&quot;">​</a></h4><p><strong>Rolle</strong>: Nur-Lese-Technologieberater, Experte für hochintelligentes Reasoning</p><p><strong>Fähigkeiten</strong>:</p><ul><li>Architekturentscheidungsempfehlungen</li><li>Diagnose komplexer Probleme</li><li>Code-Review (nur Lesen)</li><li>Multi-System-Abwägungsanalyse</li></ul><p><strong>Empfohlenes Modell</strong>: <code>openai/gpt-5.2</code> (temperature: 0.1)</p><p><strong>Anwendungsszenarien</strong>:</p><ul><li>Komplexes Architekturdesign</li><li>Selbstüberprüfung nach Abschluss wichtiger Arbeiten</li><li>Schwieriges Debugging nach 2+ fehlgeschlagenen Reparaturversuchen</li><li>Unbekannte Code-Muster oder Architekturen</li><li>Sicherheits-/Performance-bezogene Probleme</li></ul><p><strong>Auslösebedingungen</strong>:</p><ul><li>Prompt enthält <code>@oracle</code> oder verwendet <code>delegate_task(agent=&quot;oracle&quot;)</code></li><li>Automatische Empfehlung bei komplexen Architekturentscheidungen</li></ul><p><strong>Einschränkungen</strong>: Nur-Lese-Berechtigungen (write, edit, task, delegate_task verboten)</p><p><strong>Kernprinzipien</strong>:</p><ul><li><strong>Minimalismus</strong>: Bevorzugt die einfachste Lösung</li><li><strong>Nutzung vorhandener Ressourcen</strong>: Priorisiert Modifikation des aktuellen Codes, vermeidet neue Abhängigkeiten</li><li><strong>Developer Experience First</strong>: Lesbarkeit, Wartbarkeit &gt; theoretische Performance</li><li><strong>Einzelner klarer Pfad</strong>: Bietet eine Hauptempfehlung, nur bei signifikanten Abwägungsunterschieden alternative Ansätze</li></ul><hr><h4 id="metis-pre-planning-analyst" tabindex="-1">Metis - Pre-Planning-Analyst <a class="header-anchor" href="#metis-pre-planning-analyst" aria-label="Permalink to &quot;Metis - Pre-Planning-Analyst&quot;">​</a></h4><p><strong>Rolle</strong>: Experte für Anforderungsanalyse und Risikobewertung vor der Planung</p><p><strong>Fähigkeiten</strong>:</p><ul><li>Identifizierung versteckter Anforderungen und unklarer Vorgaben</li><li>Erkennung von Mehrdeutigkeiten, die zu KI-Fehlern führen können</li><li>Markierung potenzieller AI-Slop-Muster (Over-Engineering, Scope Creep)</li><li>Vorbereitung von Anweisungen für Planungsagenten</li></ul><p><strong>Empfohlenes Modell</strong>: <code>anthropic/claude-sonnet-4-5</code> (temperature: 0.3)</p><p><strong>Anwendungsszenarien</strong>:</p><ul><li>Vor der Prometheus-Planung</li><li>Wenn Benutzeranfragen vage oder offen sind</li><li>Verhinderung von KI-Over-Engineering-Mustern</li></ul><p><strong>Aufrufmethode</strong>: Automatischer Aufruf durch Prometheus (Interview-Modus)</p><p><strong>Einschränkungen</strong>: Nur-Lese-Berechtigungen (write, edit, task, delegate_task verboten)</p><p><strong>Kernprozess</strong>:</p><ol><li><strong>Intent-Klassifizierung</strong>: Refactoring / Von Grund auf neu / Mittlere Aufgabe / Kollaboration / Architektur / Forschung</li><li><strong>Intent-spezifische Analyse</strong>: Bietet gezielte Empfehlungen basierend auf verschiedenen Typen</li><li><strong>Fragengenerierung</strong>: Generiert klare Fragen für den Benutzer</li><li><strong>Anweisungsvorbereitung</strong>: Generiert klare &quot;MUST&quot; und &quot;MUST NOT&quot; Anweisungen für Prometheus</li></ol><hr><h4 id="momus-plan-reviewer" tabindex="-1">Momus - Plan-Reviewer <a class="header-anchor" href="#momus-plan-reviewer" aria-label="Permalink to &quot;Momus - Plan-Reviewer&quot;">​</a></h4><p><strong>Rolle</strong>: Strenger Plan-Review-Experte, findet alle Lücken und Unklarheiten</p><p><strong>Fähigkeiten</strong>:</p><ul><li>Validierung der Klarheit, Überprüfbarkeit und Vollständigkeit von Plänen</li><li>Überprüfung aller Dateireferenzen und Kontexte</li><li>Simulation tatsächlicher Implementierungsschritte</li><li>Identifizierung kritischer Lücken</li></ul><p><strong>Empfohlenes Modell</strong>: <code>anthropic/claude-sonnet-4-5</code> (temperature: 0.1)</p><p><strong>Anwendungsszenarien</strong>:</p><ul><li>Nach Erstellung eines Arbeitsplans durch Prometheus</li><li>Vor Ausführung komplexer TODO-Listen</li><li>Validierung der Planqualität</li></ul><p><strong>Aufrufmethode</strong>: Automatischer Aufruf durch Prometheus</p><p><strong>Einschränkungen</strong>: Nur-Lese-Berechtigungen (write, edit, task, delegate_task verboten)</p><p><strong>Vier Hauptbewertungskriterien</strong>:</p><ol><li><strong>Klarheit der Arbeitsinhalte</strong>: Gibt jede Aufgabe eine Referenzquelle an?</li><li><strong>Validierungs- und Akzeptanzkriterien</strong>: Gibt es konkrete Erfolgsprüfungsmethoden?</li><li><strong>Kontextvollständigkeit</strong>: Wird ausreichend Kontext bereitgestellt (90% Konfidenzschwelle)?</li><li><strong>Gesamtverständnis</strong>: Versteht der Entwickler WARUM, WAS und WIE?</li></ol><p><strong>Kernprinzip</strong>: <strong>Dokumenten-Reviewer, kein Design-Berater</strong>. Bewertet &quot;Ist der Plan klar genug zur Ausführung&quot;, nicht &quot;Ist die gewählte Methode korrekt&quot;.</p><hr><h3 id="forschung-und-exploration-3" tabindex="-1">Forschung und Exploration (3) <a class="header-anchor" href="#forschung-und-exploration-3" aria-label="Permalink to &quot;Forschung und Exploration (3)&quot;">​</a></h3><h4 id="librarian-multi-repository-forschungsexperte" tabindex="-1">Librarian - Multi-Repository-Forschungsexperte <a class="header-anchor" href="#librarian-multi-repository-forschungsexperte" aria-label="Permalink to &quot;Librarian - Multi-Repository-Forschungsexperte&quot;">​</a></h4><p><strong>Rolle</strong>: Experte für das Verständnis von Open-Source-Repositories, spezialisiert auf das Finden von Dokumentation und Implementierungsbeispielen</p><p><strong>Fähigkeiten</strong>:</p><ul><li>GitHub CLI: Repositories klonen, Issues/PRs durchsuchen, Historie anzeigen</li><li>Context7: Offizielle Dokumentation abfragen</li><li>Web Search: Neueste Informationen suchen</li><li>Generierung von Beweisen mit permanenten Links</li></ul><p><strong>Empfohlenes Modell</strong>: <code>opencode/big-pickle</code> (temperature: 0.1)</p><p><strong>Anwendungsszenarien</strong>:</p><ul><li>&quot;Wie verwendet man [Bibliothek]?&quot;</li><li>&quot;Was sind die Best Practices für [Framework-Feature]?&quot;</li><li>&quot;Warum verhält sich [externe Abhängigkeit] so?&quot;</li><li>&quot;Finde Verwendungsbeispiele für [Bibliothek]&quot;</li></ul><p><strong>Auslösebedingungen</strong>:</p><ul><li>Automatischer Trigger bei Erwähnung externer Bibliotheken/Quellen</li><li>Prompt enthält <code>@librarian</code></li></ul><p><strong>Anforderungstyp-Klassifizierung</strong>:</p><ul><li><strong>Typ A (Konzeptionell)</strong>: &quot;Wie macht man X?&quot;, &quot;Best Practices&quot;</li><li><strong>Typ B (Implementierungsreferenz)</strong>: &quot;Wie implementiert X Y?&quot;, &quot;Zeige Quellcode von Z&quot;</li><li><strong>Typ C (Kontext und Historie)</strong>: &quot;Warum wurde das so geändert?&quot;, &quot;Historie von X?&quot;</li><li><strong>Typ D (Umfassende Forschung)</strong>: Komplexe/vage Anfragen</li></ul><p><strong>Einschränkungen</strong>: Nur-Lese-Berechtigungen (write, edit, task, delegate_task, call_omo_agent verboten)</p><p><strong>Zwingende Anforderung</strong>: Alle Code-Aussagen müssen GitHub-Permalinks enthalten</p><hr><h4 id="explore-schneller-codebase-explorations-experte" tabindex="-1">Explore - Schneller Codebase-Explorations-Experte <a class="header-anchor" href="#explore-schneller-codebase-explorations-experte" aria-label="Permalink to &quot;Explore - Schneller Codebase-Explorations-Experte&quot;">​</a></h4><p><strong>Rolle</strong>: Kontextbewusster Code-Such-Experte</p><p><strong>Fähigkeiten</strong>:</p><ul><li>LSP-Tools: Definitionen, Referenzen, Symbolnavigation</li><li>AST-Grep: Strukturelle Mustersuche</li><li>Grep: Textmustersuche</li><li>Glob: Dateinamenmuster-Matching</li><li>Parallele Ausführung (3+ Tools gleichzeitig)</li></ul><p><strong>Empfohlenes Modell</strong>: <code>opencode/gpt-5-nano</code> (temperature: 0.1)</p><p><strong>Anwendungsszenarien</strong>:</p><ul><li>Breite Suche mit 2+ Suchperspektiven erforderlich</li><li>Unbekannte Modulstruktur</li><li>Cross-Layer-Mustererkennung</li><li>Finden von &quot;Wo ist X?&quot;, &quot;Welche Datei hat Y?&quot;</li></ul><p><strong>Auslösebedingungen</strong>:</p><ul><li>Automatischer Trigger bei Beteiligung von 2+ Modulen</li><li>Prompt enthält <code>@explore</code></li></ul><p><strong>Erzwungenes Ausgabeformat</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;analysis&gt;</span></span>
<span class="line"><span>**Literal Request**: [Wörtliche Benutzeranfrage]</span></span>
<span class="line"><span>**Actual Need**: [Was tatsächlich benötigt wird]</span></span>
<span class="line"><span>**Success Looks Like**: [Wie Erfolg aussehen sollte]</span></span>
<span class="line"><span>&lt;/analysis&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;results&gt;</span></span>
<span class="line"><span>&lt;files&gt;</span></span>
<span class="line"><span>- /absolute/path/to/file1.ts — [Warum diese Datei relevant ist]</span></span>
<span class="line"><span>- /absolute/path/to/file2.ts — [Warum diese Datei relevant ist]</span></span>
<span class="line"><span>&lt;/files&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;answer&gt;</span></span>
<span class="line"><span>[Direkte Antwort auf den tatsächlichen Bedarf]</span></span>
<span class="line"><span>&lt;/answer&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;next_steps&gt;</span></span>
<span class="line"><span>[Was als nächstes zu tun ist]</span></span>
<span class="line"><span>&lt;/next_steps&gt;</span></span>
<span class="line"><span>&lt;/results&gt;</span></span></code></pre></div><p><strong>Einschränkungen</strong>: Nur-Lese-Berechtigungen (write, edit, task, delegate_task, call_omo_agent verboten)</p><hr><h4 id="multimodal-looker-medienanalyse-experte" tabindex="-1">Multimodal Looker - Medienanalyse-Experte <a class="header-anchor" href="#multimodal-looker-medienanalyse-experte" aria-label="Permalink to &quot;Multimodal Looker - Medienanalyse-Experte&quot;">​</a></h4><p><strong>Rolle</strong>: Interpretiert Mediendateien, die nicht als reiner Text gelesen werden können</p><p><strong>Fähigkeiten</strong>:</p><ul><li>PDF: Text, Struktur, Tabellen, spezifische Kapitel-Daten extrahieren</li><li>Bilder: Layout, UI-Elemente, Text, Diagramme beschreiben</li><li>Diagramme: Beziehungen, Abläufe, Architekturen erklären</li></ul><p><strong>Empfohlenes Modell</strong>: <code>google/gemini-3-flash</code> (temperature: 0.1)</p><p><strong>Anwendungsszenarien</strong>:</p><ul><li>Strukturierte Daten aus PDFs extrahieren</li><li>UI-Elemente oder Diagramme in Bildern beschreiben</li><li>Diagramme in technischer Dokumentation analysieren</li></ul><p><strong>Aufrufmethode</strong>: Automatischer Trigger über <code>look_at</code>-Tool</p><p><strong>Einschränkungen</strong>: <strong>Nur-Lese-Whitelist</strong> (nur read-Tool erlaubt)</p><hr><h3 id="planung-und-ausfuhrung-2" tabindex="-1">Planung und Ausführung (2) <a class="header-anchor" href="#planung-und-ausfuhrung-2" aria-label="Permalink to &quot;Planung und Ausführung (2)&quot;">​</a></h3><h4 id="prometheus-strategischer-planer" tabindex="-1">Prometheus - Strategischer Planer <a class="header-anchor" href="#prometheus-strategischer-planer" aria-label="Permalink to &quot;Prometheus - Strategischer Planer&quot;">​</a></h4><p><strong>Rolle</strong>: Experte für Interview-basierte Anforderungserhebung und Arbeitsplan-Generierung</p><p><strong>Fähigkeiten</strong>:</p><ul><li>Interview-Modus: Kontinuierliches Fragen bis Anforderungen klar sind</li><li>Arbeitsplan-Generierung: Strukturierte Markdown-Plandokumente</li><li>Parallele Delegation: Oracle, Metis, Momus zur Planvalidierung konsultieren</li></ul><p><strong>Empfohlenes Modell</strong>: <code>anthropic/claude-opus-4-5</code> (temperature: 0.1)</p><p><strong>Anwendungsszenarien</strong>:</p><ul><li>Detaillierte Pläne für komplexe Projekte erstellen</li><li>Projekte mit klärungsbedürftigen Anforderungen</li><li>Systematische Arbeitsabläufe</li></ul><p><strong>Aufrufmethode</strong>:</p><ul><li>Prompt enthält <code>@prometheus</code> oder &quot;Prometheus verwenden&quot;</li><li>Verwendung des Slash-Befehls <code>/start-work</code></li></ul><p><strong>Workflow</strong>:</p><ol><li><strong>Interview-Modus</strong>: Kontinuierliches Fragen bis Anforderungen klar sind</li><li><strong>Plan-Entwurf</strong>: Strukturierten Markdown-Plan generieren</li><li><strong>Parallele Delegation</strong>: <ul><li><code>delegate_task(agent=&quot;oracle&quot;, prompt=&quot;Architekturentscheidungen überprüfen&quot;)</code> → Hintergrund</li><li><code>delegate_task(agent=&quot;metis&quot;, prompt=&quot;Potenzielle Risiken identifizieren&quot;)</code> → Hintergrund</li><li><code>delegate_task(agent=&quot;momus&quot;, prompt=&quot;Planvollständigkeit validieren&quot;)</code> → Hintergrund</li></ul></li><li><strong>Feedback integrieren</strong>: Plan verfeinern</li><li><strong>Plan ausgeben</strong>: In <code>.sisyphus/plans/{name}.md</code> speichern</li></ol><p><strong>Einschränkungen</strong>: Nur Planung, keine Code-Implementierung (erzwungen durch <code>prometheus-md-only</code> Hook)</p><hr><h4 id="sisyphus-junior-aufgaben-executor" tabindex="-1">Sisyphus Junior - Aufgaben-Executor <a class="header-anchor" href="#sisyphus-junior-aufgaben-executor" aria-label="Permalink to &quot;Sisyphus Junior - Aufgaben-Executor&quot;">​</a></h4><p><strong>Rolle</strong>: Kategorie-generierter Sub-Agent-Executor</p><p><strong>Fähigkeiten</strong>:</p><ul><li>Erbt Category-Konfiguration (Modell, temperature, prompt_append)</li><li>Lädt Skills (spezialisierte Fähigkeiten)</li><li>Führt delegierte Unteraufgaben aus</li></ul><p><strong>Empfohlenes Modell</strong>: Erbt von Category (Standard <code>anthropic/claude-sonnet-4-5</code>)</p><p><strong>Anwendungsszenarien</strong>:</p><ul><li>Automatische Generierung bei Verwendung von <code>delegate_task(category=&quot;...&quot;, skills=[&quot;...&quot;])</code></li><li>Aufgaben, die spezifische Category- und Skill-Kombinationen erfordern</li><li>Leichtgewichtige schnelle Aufgaben (&quot;quick&quot; Category verwendet Haiku-Modell)</li></ul><p><strong>Aufrufmethode</strong>: Automatische Generierung über <code>delegate_task</code>-Tool</p><p><strong>Einschränkungen</strong>: task, delegate_task verboten (keine erneute Delegation)</p><hr><h2 id="schnellreferenz-fur-agent-aufrufe" tabindex="-1">Schnellreferenz für Agent-Aufrufe <a class="header-anchor" href="#schnellreferenz-fur-agent-aufrufe" aria-label="Permalink to &quot;Schnellreferenz für Agent-Aufrufe&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Aufrufmethode</th><th>Auslösebedingung</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>Standard-Hauptagent</td><td>Tägliche Entwicklungsaufgaben</td></tr><tr><td><strong>Atlas</strong></td><td><code>/start-work</code> Befehl</td><td>Projektausführung starten</td></tr><tr><td><strong>Oracle</strong></td><td><code>@oracle</code> oder <code>delegate_task(agent=&quot;oracle&quot;)</code></td><td>Komplexe Architekturentscheidungen, 2+ fehlgeschlagene Reparaturen</td></tr><tr><td><strong>Librarian</strong></td><td><code>@librarian</code> oder <code>delegate_task(agent=&quot;librarian&quot;)</code></td><td>Automatischer Trigger bei Erwähnung externer Bibliotheken/Quellen</td></tr><tr><td><strong>Explore</strong></td><td><code>@explore</code> oder <code>delegate_task(agent=&quot;explore&quot;)</code></td><td>Automatischer Trigger bei Beteiligung von 2+ Modulen</td></tr><tr><td><strong>Multimodal Looker</strong></td><td><code>look_at</code> Tool</td><td>Bei Bedarf zur Analyse von PDF/Bildern</td></tr><tr><td><strong>Prometheus</strong></td><td><code>@prometheus</code> oder <code>/start-work</code></td><td>Prompt enthält &quot;Prometheus&quot; oder Planung erforderlich</td></tr><tr><td><strong>Metis</strong></td><td>Automatischer Aufruf durch Prometheus</td><td>Automatische Analyse vor Planung</td></tr><tr><td><strong>Momus</strong></td><td>Automatischer Aufruf durch Prometheus</td><td>Automatische Überprüfung nach Plan-Generierung</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td><code>delegate_task(category=...)</code></td><td>Automatische Generierung bei Verwendung von Category/Skill</td></tr></tbody></table><hr><h2 id="wann-welchen-agenten-verwenden" tabindex="-1">Wann welchen Agenten verwenden <a class="header-anchor" href="#wann-welchen-agenten-verwenden" aria-label="Permalink to &quot;Wann welchen Agenten verwenden&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Schneller Entscheidungsbaum</p><p><strong>Szenario 1: Tägliche Entwicklung (Code schreiben, Bugs fixen)</strong> → <strong>Sisyphus</strong> (Standard)</p><p><strong>Szenario 2: Komplexe Architekturentscheidungen</strong> → <strong>@oracle</strong> konsultieren</p><p><strong>Szenario 3: Dokumentation oder Implementierung externer Bibliotheken finden</strong> → <strong>@librarian</strong> oder automatischer Trigger</p><p><strong>Szenario 4: Unbekannte Codebase, relevanten Code finden</strong> → <strong>@explore</strong> oder automatischer Trigger (2+ Module)</p><p><strong>Szenario 5: Komplexes Projekt benötigt detaillierten Plan</strong> → <strong>@prometheus</strong> oder <code>/start-work</code> verwenden</p><p><strong>Szenario 6: PDF oder Bild analysieren</strong> → <strong>look_at</strong> Tool (automatischer Trigger für Multimodal Looker)</p><p><strong>Szenario 7: Schnelle einfache Aufgabe, Kosten sparen</strong> → <code>delegate_task(category=&quot;quick&quot;)</code></p><p><strong>Szenario 8: Git-Spezialoperationen erforderlich</strong> → <code>delegate_task(category=&quot;quick&quot;, skills=[&quot;git-master&quot;])</code></p><p><strong>Szenario 9: Frontend-UI-Design erforderlich</strong> → <code>delegate_task(category=&quot;visual-engineering&quot;)</code></p><p><strong>Szenario 10: Hochintelligente Reasoning-Aufgabe erforderlich</strong> → <code>delegate_task(category=&quot;ultrabrain&quot;)</code></p></div><hr><h2 id="beispiele-fur-agent-zusammenarbeit-vollstandiger-workflow" tabindex="-1">Beispiele für Agent-Zusammenarbeit: Vollständiger Workflow <a class="header-anchor" href="#beispiele-fur-agent-zusammenarbeit-vollstandiger-workflow" aria-label="Permalink to &quot;Beispiele für Agent-Zusammenarbeit: Vollständiger Workflow&quot;">​</a></h2><h3 id="beispiel-1-komplexe-feature-entwicklung" tabindex="-1">Beispiel 1: Komplexe Feature-Entwicklung <a class="header-anchor" href="#beispiel-1-komplexe-feature-entwicklung" aria-label="Permalink to &quot;Beispiel 1: Komplexe Feature-Entwicklung&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzer: Entwickle ein Benutzerauthentifizierungssystem</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Sisyphus empfängt Aufgabe</span></span>
<span class="line"><span>  → Analysiert Anforderungen, erkennt Bedarf an externer Bibliothek (JWT)</span></span>
<span class="line"><span>  → Parallele Delegation:</span></span>
<span class="line"><span>    - @librarian: &quot;Finde Next.js JWT Best Practices&quot; → [Hintergrund]</span></span>
<span class="line"><span>    - @explore: &quot;Finde bestehenden authentifizierungsbezogenen Code&quot; → [Hintergrund]</span></span>
<span class="line"><span>  → Wartet auf Ergebnisse, integriert Informationen</span></span>
<span class="line"><span>  → Implementiert JWT-Authentifizierungsfunktion</span></span>
<span class="line"><span>  → Nach Abschluss Delegation:</span></span>
<span class="line"><span>    - @oracle: &quot;Architekturdesign überprüfen&quot; → [Hintergrund]</span></span>
<span class="line"><span>  → Optimiert basierend auf Empfehlungen</span></span></code></pre></div><hr><h3 id="beispiel-2-projektplanung" tabindex="-1">Beispiel 2: Projektplanung <a class="header-anchor" href="#beispiel-2-projektplanung" aria-label="Permalink to &quot;Beispiel 2: Projektplanung&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzer: Verwende Prometheus zur Planung dieses Projekts</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Prometheus empfängt Aufgabe</span></span>
<span class="line"><span>  → Interview-Modus:</span></span>
<span class="line"><span>    - Frage 1: Was sind die Kernfunktionen?</span></span>
<span class="line"><span>    - [Benutzerantwort]</span></span>
<span class="line"><span>    - Frage 2: Zielbenutzergruppe?</span></span>
<span class="line"><span>    - [Benutzerantwort]</span></span>
<span class="line"><span>    - ...</span></span>
<span class="line"><span>  → Nach Klärung der Anforderungen, parallele Delegation:</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;oracle&quot;, prompt=&quot;Architekturentscheidungen überprüfen&quot;) → [Hintergrund]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;metis&quot;, prompt=&quot;Potenzielle Risiken identifizieren&quot;) → [Hintergrund]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;momus&quot;, prompt=&quot;Planvollständigkeit validieren&quot;) → [Hintergrund]</span></span>
<span class="line"><span>  → Wartet auf Abschluss aller Hintergrundaufgaben</span></span>
<span class="line"><span>  → Integriert Feedback, verfeinert Plan</span></span>
<span class="line"><span>  → Gibt Markdown-Plandokument aus</span></span>
<span class="line"><span>→ Benutzer überprüft Plan, bestätigt</span></span>
<span class="line"><span>→ Verwendet /start-work zur Ausführung</span></span></code></pre></div><hr><h2 id="agent-berechtigungen-und-einschrankungen" tabindex="-1">Agent-Berechtigungen und Einschränkungen <a class="header-anchor" href="#agent-berechtigungen-und-einschrankungen" aria-label="Permalink to &quot;Agent-Berechtigungen und Einschränkungen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>write</th><th>edit</th><th>bash</th><th>delegate_task</th><th>webfetch</th><th>read</th><th>LSP</th><th>AST-Grep</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Atlas</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Oracle</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Librarian</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Explore</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Multimodal Looker</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Prometheus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Metis</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Momus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td>✅</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><hr><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><p>Die 10 KI-Agenten von oh-my-opencode decken alle Aspekte des Entwicklungsprozesses ab:</p><ul><li><strong>Orchestrierung und Ausführung</strong>: Sisyphus (Hauptorchestrator), Atlas (TODO-Management)</li><li><strong>Beratung und Review</strong>: Oracle (Strategischer Berater), Metis (Pre-Planning-Analyse), Momus (Plan-Review)</li><li><strong>Forschung und Exploration</strong>: Librarian (Multi-Repository-Forschung), Explore (Codebase-Exploration), Multimodal Looker (Medienanalyse)</li><li><strong>Planung</strong>: Prometheus (Strategische Planung), Sisyphus Junior (Unteraufgaben-Ausführung)</li></ul><p><strong>Kernpunkte</strong>:</p><ol><li>Behandeln Sie KI nicht als Alleskönner, sondern als professionelles Team</li><li>Wählen Sie den am besten geeigneten Agenten basierend auf dem Aufgabentyp</li><li>Nutzen Sie parallele Delegation zur Effizienzsteigerung (Librarian, Explore, Oracle können im Hintergrund laufen)</li><li>Verstehen Sie die Berechtigungsbeschränkungen jedes Agenten (Nur-Lese-Agenten können keinen Code ändern)</li><li>Zusammenarbeit zwischen Agenten kann vollständige Workflows bilden (Planung → Ausführung → Review)</li></ol><hr><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../prometheus-planning/">Prometheus-Planung: Interview-basierte Anforderungserhebung</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie man Prometheus für Interview-basierte Anforderungserhebung verwendet</li><li>Wie man strukturierte Arbeitspläne generiert</li><li>Wie man Metis und Momus zur Planvalidierung einsetzt</li><li>Wie man Hintergrundaufgaben abruft und abbricht</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Agent</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Sisyphus Hauptorchestrator</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus.ts</code></a></td><td>-</td></tr><tr><td>Atlas Hauptorchestrator</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/atlas.ts" target="_blank" rel="noreferrer"><code>src/agents/atlas.ts</code></a></td><td>-</td></tr><tr><td>Oracle Berater</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/oracle.ts" target="_blank" rel="noreferrer"><code>src/agents/oracle.ts</code></a></td><td>1-123</td></tr><tr><td>Librarian Forschungsexperte</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/librarian.ts" target="_blank" rel="noreferrer"><code>src/agents/librarian.ts</code></a></td><td>1-327</td></tr><tr><td>Explore Such-Experte</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/explore.ts" target="_blank" rel="noreferrer"><code>src/agents/explore.ts</code></a></td><td>1-123</td></tr><tr><td>Multimodal Looker</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/multimodal-looker.ts" target="_blank" rel="noreferrer"><code>src/agents/multimodal-looker.ts</code></a></td><td>1-57</td></tr><tr><td>Prometheus Planer</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/prometheus-prompt.ts" target="_blank" rel="noreferrer"><code>src/agents/prometheus-prompt.ts</code></a></td><td>1-1196</td></tr><tr><td>Metis Pre-Planning-Analyse</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/metis.ts" target="_blank" rel="noreferrer"><code>src/agents/metis.ts</code></a></td><td>1-316</td></tr><tr><td>Momus Plan-Reviewer</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/momus.ts" target="_blank" rel="noreferrer"><code>src/agents/momus.ts</code></a></td><td>1-445</td></tr><tr><td>Sisyphus Junior</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus-junior.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus-junior.ts</code></a></td><td>-</td></tr><tr><td>Agent-Metadaten-Definition</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/types.ts" target="_blank" rel="noreferrer"><code>src/agents/types.ts</code></a></td><td>-</td></tr><tr><td>Agent-Tool-Einschränkungen</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/shared/permission-compat.ts" target="_blank" rel="noreferrer"><code>src/shared/permission-compat.ts</code></a></td><td>-</td></tr></tbody></table><p><strong>Schlüsselkonfigurationen</strong>:</p><ul><li><code>ORACLE_PROMPT_METADATA</code>: Oracle-Agent-Metadaten (Auslösebedingungen, Anwendungsszenarien)</li><li><code>LIBRARIAN_PROMPT_METADATA</code>: Librarian-Agent-Metadaten</li><li><code>EXPLORE_PROMPT_METADATA</code>: Explore-Agent-Metadaten</li><li><code>MULTIMODAL_LOOKER_PROMPT_METADATA</code>: Multimodal Looker-Agent-Metadaten</li><li><code>METIS_SYSTEM_PROMPT</code>: Metis-Agent-System-Prompt</li><li><code>MOMUS_SYSTEM_PROMPT</code>: Momus-Agent-System-Prompt</li></ul><p><strong>Schlüsselfunktionen</strong>:</p><ul><li><code>createOracleAgent(model)</code>: Oracle-Agent-Konfiguration erstellen</li><li><code>createLibrarianAgent(model)</code>: Librarian-Agent-Konfiguration erstellen</li><li><code>createExploreAgent(model)</code>: Explore-Agent-Konfiguration erstellen</li><li><code>createMultimodalLookerAgent(model)</code>: Multimodal Looker-Agent-Konfiguration erstellen</li><li><code>createMetisAgent(model)</code>: Metis-Agent-Konfiguration erstellen</li><li><code>createMomusAgent(model)</code>: Momus-Agent-Konfiguration erstellen</li></ul><p><strong>Berechtigungsbeschränkungen</strong>:</p><ul><li><code>createAgentToolRestrictions()</code>: Agent-Tool-Einschränkungen erstellen (verwendet von Oracle, Librarian, Explore, Metis, Momus)</li><li><code>createAgentToolAllowlist()</code>: Agent-Tool-Whitelist erstellen (verwendet von Multimodal Looker)</li></ul></details>`,160)])])}const h=n(a,[["render",i]]);export{c as __pageData,h as default};
